// 短信验证码场景
export const SMS_SCENE = {
  LOGIN: 'login',                   // 登录
  REGISTER: 'register',             // 注册
  RESET_PASSWORD: 'reset_password',          // 重置密码
  CHANGE_PHONE: 'change_phone',     // 更换手机号，修改为 change_phone
}

// 核心模块（默认显示）
export const CORE_MODULES = [
  'basic_info',
  'job_intention',
  'work_experience',
  'education'
]

// 可选模块（在"添加更多"中显示）
export const OPTIONAL_MODULES = [
  'project_experience',
  'skills',
  'certificates',
  'awards',
  'languages',
  'interests'
]
